457: // Start starts all components of the error serving tap http serverPilot discovery service on the port specified in DiscoveryServerOptions.
458: // If Port == 0, a port number is automatically chosen. Content serving is started by this method,
459: // but is executed asynchronously. Serving can be canceled at any time by closing the provided stop channel.
460: func (s *Server) Start(stop <-chan struct{}) error {
461: 	log.Infof("Starting Istiod Server with primary cluster %s", s.clusterID)
462: 
463: 	if features.UnsafeFeaturesEnabled() {
464: 		log.Warn("Server is starting with unsafe features enabled")
465: 	}
466: 
467: 	// Now start all of the components.
468: 	if err := s.server.Start(stop); err != nil {
469: 		return err
470: 	}
471: 	if !s.waitForCacheSync(stop) {
472: 		return fmt.Errorf("failed to sync cache")
473: 	}
474: 	// Inform Discovery Server so that it can start accepting connections.
475: 	s.XDSServer.CachesSynced()
476: 
477: 	// Race condition - if waitForCache is too fast and we run this as a startup function,
478: 	// the grpc server would be started before CA is registered. Listening should be last.
479: 	if s.secureGrpcAddress != "" {
480: 		grpcListener, err := net.Listen("tcp", s.secureGrpcAddress)
481: 		if err != nil {
482: 			return err
483: 		}
484: 		go func() {
485: 			log.Infof("starting secure gRPC discovery service at %s", grpcListener.Addr())
486: 			if err := s.secureGrpcServer.Serve(grpcListener); err != nil {
487: 				log.Errorf("error serving secure GRPC server: %v", err)
488: 			}
489: 		}()
490: 	}
491: 
492: 	if s.grpcAddress != "" {
493: 		grpcListener, err := net.Listen("tcp", s.grpcAddress)
494: 		if err != nil {
495: 			return err
496: 		}
497: 		go func() {
498: 			log.Infof("starting gRPC discovery service at %s", grpcListener.Addr())
499: 			if err := s.grpcServer.Serve(grpcListener); err != nil {
500: 				log.Errorf("error serving GRPC server: %v", err)
501: 			}
502: 		}()
503: 	}
504: 
505: 	if s.httpsServer != nil {
506: 		httpsListener, err := net.Listen("tcp", s.httpsServer.Addr)
507: 		if err != nil {
508: 			return err
509: 		}
510: 		go func() {
511: 			log.Infof("starting webhook service at %s", httpsListener.Addr())
512: 			if err := s.httpsServer.ServeTLS(httpsListener, "", ""); network.IsUnexpectedListenerError(err) {
513: 				log.Errorf("error serving https server: %v", err)
514: 			}
515: 		}()
516: 		s.httpsAddr = httpsListener.Addr().String()
517: 	}
518: 
519: 	s.waitForShutdown(stop)
