func xdsNeedsPush(req *model.PushRequest, proxy *model.Proxy) (needsPush, definitive bool) {
	if proxy.Type == model.Ztunnel {
		// Not supported for ztunnel
		return false, true
	}
	if req == nil {
		return true, true
