   537→		log.Warnf("skipping Kubernetes credential reader; PILOT_ENABLE_XDS_IDENTITY_CHECK must be set to true for this feature.")
   538→	} else {
   539→		creds := kubecredentials.NewMulticluster(s.clusterID, s.multiclusterController)
   540→		creds.AddSecretHandler(func(k kind.Kind, name string, namespace string) {
   541→			s.XDSServer.ConfigUpdate(&model.PushRequest{
   542→				Full:           false,
   543→				ConfigsUpdated: sets.New(model.ConfigKey{Kind: k, Name: name, Namespace: namespace}),
