   551→// initKubeClient creates the k8s client if running in a k8s environment.
   552→// This is determined by the presence of a kube registry, which
   553→// uses in-context k8s, or a config source of type k8s.
   554→func (s *Server) initKubeClient(args *PilotArgs) error {
   555→	if s.kubeClient != nil {
   556→		// Already initialized by startup arguments
   557→		return nil
   558→	}
   559→	hasK8SConfigStore := false
   560→	if args.RegistryOptions.FileDir == "" {
   561→		// If file dir is set - config controller will just use file.
   562→		if _, err := os.Stat(args.MeshConfigFile); !os.IsNotExist(err) {
   563→			meshConfig, err := mesh.ReadMeshConfig(args.MeshConfigFile)
   564→			if err != nil {
   565→				return fmt.Errorf("failed reading mesh config: %v", err)
   566→			}
   567→			if len(meshConfig.ConfigSources) == 0 && args.RegistryOptions.KubeConfig != "" {
   568→				hasK8SConfigStore = true
   569→			}
   570→			for _, cs := range meshConfig.ConfigSources {
   571→				if cs.Address == string(Kubernetes)+"://" {
   572→					hasK8SConfigStore = true
   573→					break
   574→				}
   575→			}
   576→		} else if args.RegistryOptions.KubeConfig != "" {
   577→			hasK8SConfigStore = true
   578→		}
   579→	}
   580→
   581→	if hasK8SConfigStore || hasKubeRegistry(args.RegistryOptions.Registries) {
   582→		// Used by validation
   583→		kubeRestConfig, err := kubelib.DefaultRestConfig(args.RegistryOptions.KubeConfig, "", func(config *rest.Config) {
   584→			config.QPS = args.RegistryOptions.KubeOptions.KubernetesAPIQPS
   585→			config.Burst = args.RegistryOptions.KubeOptions.KubernetesAPIBurst
   586→		})
   587→		if err != nil {
   588→			return fmt.Errorf("failed creating kube config: %v", err)
   589→		}
   590→
   591→		s.kubeClient, err = kubelib.NewClient(kubelib.NewClientConfigForRestConfig(kubeRestConfig), s.clusterID)
   592→		if err != nil {
   593→			return fmt.Errorf("failed creating kube client: %v", err)
   594→		}
   595→		s.kubeClient = kubelib.EnableCrdWatcher(s.kubeClient)
   596→	}
   597→
   598→	return nil
   599→}
