   768→// initialize secureGRPCServer.
   769→func (s *Server) initSecureDiscoveryService(args *PilotArgs, trustDomain string) error {
   770→	if args.ServerOptions.SecureGRPCAddr == "" {
   771→		log.Info("The secure discovery port is disabled, multiplexing on httpAddr ")
   772→		return nil
   773→	}
   774→
   775→	peerCertVerifier, err := s.createPeerCertVerifier(args.ServerOptions.TLSOptions, trustDomain)
   776→	if err != nil {
   777→		return err
   778→	}
   779→	if peerCertVerifier == nil {
   780→		// Running locally without configured certs - no TLS mode
   781→		log.Warnf("The secure discovery service is disabled")
   782→		return nil
   783→	}
   784→	log.Info("initializing secure discovery service")
   785→
   786→	cfg := &tls.Config{
   787→		GetCertificate: s.getIstiodCertificate,
   788→		ClientAuth:     tls.VerifyClientCertIfGiven,
   789→		ClientCAs:      peerCertVerifier.GetGeneralCertPool(),
   790→		VerifyPeerCertificate: func(rawCerts [][]byte, verifiedChains [][]*x509.Certificate) error {
   791→			err := peerCertVerifier.VerifyPeerCert(rawCerts, verifiedChains)
   792→			if err != nil {
   793→				log.Infof("Could not verify certificate: %v", err)
   794→			}
   795→			return err
   796→		},
   797→		MinVersion:   tls.VersionTLS12,
   798→		CipherSuites: args.ServerOptions.TLSOptions.CipherSuites,
   799→	}
   800→	// Compliance for xDS server TLS.
   801→	sec_model.EnforceGoCompliance(cfg)
   802→
   803→	tlsCreds := credentials.NewTLS(cfg)
   804→
   805→	s.secureGrpcAddress = args.ServerOptions.SecureGRPCAddr
   806→
   807→	interceptors := []grpc.UnaryServerInterceptor{
   808→		// setup server prometheus monitoring (as final interceptor in chain)
   809→		grpcprom.UnaryServerInterceptor,
   810→	}
   811→	opts := istiogrpc.ServerOptions(args.KeepaliveOptions, xdspkg.RecordRecvSize, interceptors...)
   812→	opts = append(opts, grpc.Creds(tlsCreds))
   813→
   814→	s.secureGrpcServer = grpc.NewServer(opts...)
   815→	s.XDSServer.Register(s.secureGrpcServer)
   816→	reflection.Register(s.secureGrpcServer)
   817→
   818→	s.addStartFunc("secure gRPC", func(stop <-chan struct{}) error {
   819→		go func() {
   820→			<-stop
   821→			s.secureGrpcServer.Stop()
   822→		}()
   823→		return nil
   824→	})
   825→
   826→	return nil
   827→}
