   943→// initIstiodCertLoader will make sure istiodCertBundleWatcher is updating
   944→// the certs and updates Server.istiodCert - which is returned on all TLS requests.
   945→func (s *Server) initIstiodCertLoader() error {
   946→	if err := s.loadIstiodCert(); err != nil {
   947→		return fmt.Errorf("first time load IstiodCert failed: %v", err)
   948→	}
   949→	_, watchCh := s.istiodCertBundleWatcher.AddWatcher()
   950→	s.addStartFunc("reload certs", func(stop <-chan struct{}) error {
   951→		go s.reloadIstiodCert(watchCh, stop)
   952→		return nil
   953→	})
   954→	return nil
   955→}
   956→
   957→// initIstiodCerts creates Istiod certificates to be used by gRPC and webhook TLS servers
   958→// and also sets up watches to them. It also detects and sets the root certificates
   959→// for replication.
   960→//
   961→// This will also detect the root CAs (mesh trust) and set it up for Istiod as well as
   962→// namespace replication, if the controller is enabled.
   963→//
   964→// Will prefer local certificates, and fallback to using the CA to sign a fresh, temporary
   965→// certificate.
   966→func (s *Server) initIstiodCerts(args *PilotArgs, host string) error {
   967→	// Skip all certificates
   968→	var err error
   969→
   970→	s.dnsNames = getDNSNames(args, host)
   971→	if hasCustomCertArgsOrWellKnown, tlsCertPath, tlsKeyPath, caCertPath := hasCustomTLSCerts(args.ServerOptions.TLSOptions); hasCustomCertArgsOrWellKnown {
   972→		// Use the DNS certificate provided via args or in well known location.
   973→		err = s.initFileCertificateWatches(TLSOptions{
   974→			CaCertFile: caCertPath,
   975→			KeyFile:    tlsKeyPath,
   976→			CertFile:   tlsCertPath,
   977→		})
   978→		if err != nil {
   979→			// Not crashing istiod - This typically happens if certs are missing and in tests.
   980→			log.Errorf("error initializing certificate watches: %v", err)
   981→			return nil
   982→		}
   983→	} else if features.EnableCAServer && features.PilotCertProvider == constants.CertProviderIstiod {
   984→		log.Infof("initializing Istiod DNS certificates host: %s, custom host: %s", host, features.IstiodServiceCustomHost)
   985→		err = s.initDNSCertsIstiod()
   986→	} else if features.PilotCertProvider == constants.CertProviderKubernetes {
   987→		// This will not work - better to fail Istiod startup so it can be detected early.
   988→		// Unlike other failures that we can recover from, this has no mitigation, user must
   989→		// choose a different source.
   990→		// The feature didn't work for few releases, but a skip-version upgrade may still
   991→		// encounter it.
   992→		log.Fatal("PILOT_CERT_PROVIDER=kubernetes is no longer supported by upstream K8S")
   993→	} else if strings.HasPrefix(features.PilotCertProvider, constants.CertProviderKubernetesSignerPrefix) {
   994→		log.Infof("initializing Istiod DNS certificates using K8S RA:%s  host: %s, custom host: %s", features.PilotCertProvider,
   995→			host, features.IstiodServiceCustomHost)
   996→		err = s.initDNSCertsK8SRA()
   997→	} else {
   998→		log.Warnf("PILOT_CERT_PROVIDER=%s is not implemented", features.PilotCertProvider)
   999→
  1000→		// In Istio 1.22 - we return nil here - the old code in s.initDNSCerts used to have
  1001→		// an 'else' to handle the unknown providers by not initializing the TLS certs but
  1002→		// still setting the root from /etc/certs/root-cert.pem for distribution in the
  1003→		// namespace controller.
  1004→		// The new behavior appears safer - IMO we may also do a fatal unless provider is
  1005→		// set to "none" because it is not clear what the user intends.
  1006→
  1007→		// Skip invoking initIstiodCertLoader - we have no cert.
  1008→		return nil
  1009→	}
  1010→
  1011→	if err == nil {
  1012→		err = s.initIstiodCertLoader()
  1013→	}
  1014→
  1015→	return err
  1016→}
