   617→func (s *Server) initServers(args *PilotArgs) {
   618→	s.initGrpcServer(args.KeepaliveOptions)
   619→	multiplexGRPC := false
   620→	if args.ServerOptions.GRPCAddr != "" {
   621→		s.grpcAddress = args.ServerOptions.GRPCAddr
   622→	} else {
   623→		// This happens only if the GRPC port (15010) is disabled. We will multiplex
   624→		// it on the HTTP port. Does not impact the HTTPS gRPC or HTTPS.
   625→		log.Infof("multiplexing gRPC on http addr %v", args.ServerOptions.HTTPAddr)
   626→		multiplexGRPC = true
   627→	}
   628→	h2s := &http2.Server{
   629→		MaxConcurrentStreams: uint32(features.MaxConcurrentStreams),
   630→	}
   631→	multiplexHandler := h2c.NewHandler(http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
   632→		// If we detect gRPC, serve using grpcServer
   633→		if r.ProtoMajor == 2 && strings.HasPrefix(r.Header.Get("content-type"), "application/grpc") {
   634→			s.grpcServer.ServeHTTP(w, r)
   635→			return
   636→		}
   637→		// Otherwise, this is meant for the standard HTTP server
   638→		s.httpMux.ServeHTTP(w, r)
   639→	}), h2s)
   640→	s.httpServer = &http.Server{
   641→		Addr:        args.ServerOptions.HTTPAddr,
   642→		Handler:     s.httpMux,
   643→		IdleTimeout: 90 * time.Second, // matches http.DefaultTransport keep-alive timeout
   644→		ReadTimeout: 30 * time.Second,
   645→	}
   646→	if multiplexGRPC {
   647→		// To allow the gRPC handler to make per-request decision,
   648→		// use ReadHeaderTimeout instead of ReadTimeout.
   649→		s.httpServer.ReadTimeout = 0
   650→		s.httpServer.ReadHeaderTimeout = 30 * time.Second
   651→		s.httpServer.Handler = multiplexHandler
   652→	}
   653→
   654→	if args.ServerOptions.MonitoringAddr == "" {
   655→		s.monitoringMux = s.httpMux
   656→		log.Infof("initializing Istiod admin server multiplexed on httpAddr %v", s.httpServer.Addr)
   657→	} else {
   658→		log.Info("initializing Istiod admin server")
   659→	}
   660→}
