   875→// cachesSynced checks whether caches have been synced.
   876→func (s *Server) cachesSynced() bool {
   877→	if s.multiclusterController != nil && !s.multiclusterController.HasSynced() {
   878→		return false
   879→	}
   880→	if !s.ServiceController().HasSynced() {
   881→		return false
   882→	}
   883→	if !s.configController.HasSynced() {
   884→		return false
   885→	}
   886→	return true
   887→}
